mapper.sql:
SELECT A.SYSJOB_SCHDL_EXCP_ID AS jobExcSn , A.SYSJOB_SCHDL_ID AS jobSchSn , (SELECT SYSJOB_SCHDLNM FROM TB_LMS_SYSJOB_SCHDL WHERE SYSJOB_SCHDL_ID = A.SYSJOB_SCHDL_ID) AS jobSchNm , A.SBJCT_ID AS crsCreCd , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS crsCreNm , A.SYSJOB_SCHDL_SYMD AS schStartDt , A.SYSJOB_SCHDL_EYMD AS schEndDt , A.SYSJOB_SCHDL_EXCP_PROC_RSN AS excCmnt , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm FROM TB_LMS_SYSJOB_SCHDL_EXCP A WHERE 1 = 1
AND A.SYSJOB_SCHDL_EXCP_ID = #{jobExcSn}
AND A.SYSJOB_SCHDL_ID = #{jobSchSn}
AND A.SBJCT_ID = #{crsCreCd}

mapper.insert:
		/*
             SQL ID : SysJobSchExcDAO.insert
            	 설  명 : 업무일정 예외 등록
         */
         INSERT INTO TB_LMS_SYSJOB_SCHDL_EXCP (
         	  SYSJOB_SCHDL_EXCP_ID
			, SYSJOB_SCHDL_ID
			, SBJCT_ID
			, SYSJOB_SCHDL_SYMD
			, SYSJOB_SCHDL_EYMD
			, SYSJOB_SCHDL_EXCP_PROC_RSN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{jobExcSn}
         	, #{jobSchSn}
         	, #{crsCreCd}
         	, #{schStartDt}
         	, #{schEndDt}
         	, #{excCmnt}
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )

mapper.delete:
		/*
             SQL ID : SysJobSchExcDAO.delete
            	 설  명 : 업무일정 예외 삭제
         */
         DELETE FROM TB_LMS_SYSJOB_SCHDL_EXCP
          WHERE SYSJOB_SCHDL_EXCP_ID = #{jobExcSn}
